#define BLOCK_SIZE 16

__device__ int maximum(int a, int b, int c) {
    int k;
    if (b >= a)
        k = b;
    else
        k = a;

    if (c >= k)
        return c;
    else
        return k;
}

__global__ void nw_kernel_top_left(int *input_itemsets, const int *referrence, int max_cols, int blk, int penalty) {
    int b_index_x = blockIdx.x * blockDim.x + threadIdx.x;
    if (b_index_x >= blk) return;
    int b_index_y = blk - 1 - b_index_x;

    __shared__ int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    __shared__ int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    // Load reference_l
    for (int i = threadIdx.y; i < BLOCK_SIZE; i += blockDim.y) {
        for (int j = threadIdx.x; j < BLOCK_SIZE; j += blockDim.x) {
            reference_l[i * BLOCK_SIZE + j] = referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1];
        }
    }
    __syncthreads();

    // Load input_itemsets_l
    for (int i = threadIdx.y; i < BLOCK_SIZE + 1; i += blockDim.y) {
        for (int j = threadIdx.x; j < BLOCK_SIZE + 1; j += blockDim.x) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + j];
        }
    }
    __syncthreads();

    // Compute
    for (int i = 1; i <= BLOCK_SIZE; i++) {
        for (int j = 1; j <= BLOCK_SIZE; j++) {
            if (threadIdx.x == 0 && threadIdx.y == 0) {
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                    input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
            }
            __syncthreads();
        }
    }

    // Store back
    for (int i = threadIdx.y; i < BLOCK_SIZE; i += blockDim.y) {
        for (int j = threadIdx.x; j < BLOCK_SIZE; j += blockDim.x) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

__global__ void nw_kernel_bottom_right(int *input_itemsets, const int *referrence, int max_cols, int blk, int penalty) {
    int b_index_x = blockIdx.x * blockDim.x + threadIdx.x;
    int max_blk = (max_cols - 1) / BLOCK_SIZE;
    if (b_index_x < blk - 1 || b_index_x >= max_blk) return;
    int b_index_y = max_blk + blk - 2 - b_index_x;

    __shared__ int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    __shared__ int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    // Load reference_l
    for (int i = threadIdx.y; i < BLOCK_SIZE; i += blockDim.y) {
        for (int j = threadIdx.x; j < BLOCK_SIZE; j += blockDim.x) {
            reference_l[i * BLOCK_SIZE + j] = referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1];
        }
    }
    __syncthreads();

    // Load input_itemsets_l
    for (int i = threadIdx.y; i < BLOCK_SIZE + 1; i += blockDim.y) {
        for (int j = threadIdx.x; j < BLOCK_SIZE + 1; j += blockDim.x) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + j];
        }
    }
    __syncthreads();

    // Compute
    for (int i = 1; i <= BLOCK_SIZE; i++) {
        for (int j = 1; j <= BLOCK_SIZE; j++) {
            if (threadIdx.x == 0 && threadIdx.y == 0) {
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                    input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
            }
            __syncthreads();
        }
    }

    // Store back
    for (int i = threadIdx.y; i < BLOCK_SIZE; i += blockDim.y) {
        for (int j = threadIdx.x; j < BLOCK_SIZE; j += blockDim.x) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
        int max_rows, int max_cols, int penalty)
{
    int max_blk = (max_cols - 1) / BLOCK_SIZE;

    int *d_input, *d_ref;
    size_t size = max_rows * max_cols * sizeof(int);
    cudaMalloc((void**)&d_input, size);
    cudaMalloc((void**)&d_ref, size);
    cudaMemcpy(d_input, input_itemsets, size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_ref, referrence, size, cudaMemcpyHostToDevice);

    dim3 blockDim(16, 16);
    for (int blk = 1; blk <= max_blk; blk++) {
        int numBlocks = blk;
        dim3 gridDim(numBlocks, 1);
        nw_kernel_top_left<<<gridDim, blockDim>>>(d_input, d_ref, max_cols, blk, penalty);
        cudaDeviceSynchronize();
    }

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= max_blk; blk++) {
        int numBlocks = max_blk - blk + 1;
        if (numBlocks <= 0) break;
        dim3 gridDim(numBlocks, 1);
        nw_kernel_bottom_right<<<gridDim, blockDim>>>(d_input, d_ref, max_cols, blk, penalty);
        cudaDeviceSynchronize();
    }

    cudaMemcpy(input_itemsets, d_input, size, cudaMemcpyDeviceToHost);
    cudaFree(d_input);
    cudaFree(d_ref);
}

long long get_time()
{
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return t.tv_sec+t.tv_usec*1e-6;
}

void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <max_rows/max_cols> <penalty> <num_threads>\n", argv[0]);
    fprintf(stderr, "\t<dimension>      - x and y dimensions\n");
    fprintf(stderr, "\t<penalty>        - penalty(positive integer)\n");
    fprintf(stderr, "\t<num_threads>    - no. of threads\n");
    exit(1);
}

